31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	const DEDUCTIBLE = 100;
53	const CAP_MULTIPLIER = 2;
54	
55	const FIRST_INSURANCE_SURCHARGE = 0.1;
56	const CURSE_SURCHARGE = 0.5;
57	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
58	const HIGH_ENCHANTMENT_THRESHOLD = 5;
59	const LOYALTY_DISCOUNT = 0.2;
60	const LOYALTY_THRESHOLD_YEARS = 2;
61	const FOLLOWUP_DISCOUNT = 0.15;
62	const PROCESSING_FEE = 5;
63	
64	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
65	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
66	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
67	
68	// A block applies only to a group of exactly BLOCK_SIZE alike components,
69	// priced at BLOCK_PREMIUM; any other count is priced individually.
70	const componentBasePremium = (count: number, perComponent: number): number => {
71	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
72	  return count * perComponent;
73	};
74	
75	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
76	
77	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
78	const isMainItem = (item: Item): boolean => !isComponent(item);
79	
80	const countByType = (items: Item[]): Record<string, number> => {
81	  const counts: Record<string, number> = {};
82	  for (const item of items) {
83	    counts[item.type] = (counts[item.type] ?? 0) + 1;
84	  }
85	  return counts;
86	};
87	
88	// A surcharge rate is an additive percentage applied on top of a base premium.
89	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
90	
91	// A conditional rate: the given percentage when its condition holds, else 0.
92	// Used for both item surcharges and policy-wide discounts.
93	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
94	
95	// Item-specific surcharges are additive percentages of the item's base premium.
96	// First insurance applies to every item; the others only when their condition holds.
97	const itemSurchargeRate = (item: Item): number =>
98	  sum([
99	    FIRST_INSURANCE_SURCHARGE,
100	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
101	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
102	  ]);
103	
104	const mainItemPremium = (item: Item): number =>
105	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
106	
107	const componentGroupBases = (items: Item[]): number[] =>
108	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
109	    componentBasePremium(count, BASE_PREMIUM[type]),
110	  );
111	
112	// Sum of item base premiums with block pricing but no surcharges; the basis
113	// for policy-wide modifiers (loyalty, follow-up).
114	const policyBasePremium = (items: Item[]): number =>
115	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
116	  sum(componentGroupBases(items));
117	
118	// Sum of item premiums including item-specific surcharges (curse, high
119	// enchantment, first insurance).
120	const itemsPremium = (items: Item[]): number => {
121	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
122	  const componentsPremium = sum(
123	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
124	  );
125	  return mainItemsPremium + componentsPremium;
126	};
127	
128	// Policy-wide discounts are a rate applied to the unmodified policy base.
129	// Loyalty is one such discount; the follow-up-contract discount will be another.
130	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
131	
132	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
133	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
134	
135	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
136	  const surcharged = itemsPremium(items);
137	  const policyBase = policyBasePremium(items);
138	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
139	  const discount = policyWideDiscount(discountRate, policyBase);
140	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
141	};
142	
143	const insuranceSum = (items: Item[]): number =>
144	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
145	
146	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
147	
148	const claimResult = (
149	  policyItems: Item[],
150	  incident: ClaimStep["incident"],
151	): { payout: number; remainingCap: number } => {
152	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
153	  const payout = sum(incident.damages.map(damagePayout));
154	  return { payout, remainingCap: cap - payout };
155	};
156	
157	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
158	  const { yearsWithMHPCO } = scenario.customer;
159	  const policies: Record<number, Item[]> = {};
160	  let quoteCount = 0;
161	
162	  const results = scenario.steps.map((step, index) => {
163	    if (step.op === "claim") {
164	      return claimResult(policies[step.policy], step.incident);
165	    }
166	    policies[index] = step.items;
167	    const isFollowup = quoteCount > 0;
168	    quoteCount += 1;
169	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
170	  });
171	
172	  return { results };
173	};
